```class Solution {
public:
    int maxValue(int n, int index, int maxSum) {
        int l = 1, r = maxSum, res = 1;
        while (l <= r) {
            int mid = l + (r - l) / 2;
            long long sum = (long long)mid * (mid + 1) / 2;
            if (index < mid) sum -= (long long)(mid - index);
            if (n - index - 1 < mid) sum -= (long long)((mid - (n - index - 1)) * (mid - (n - index - 1) + 1)) / 2;
            if (sum <= maxSum) {
                res = mid;
                l = mid + 1;
            } else {
                r = mid - 1;
            }
        }
        return res;
    }
};
